mapper.update:
UPDATE wiki_entity
SET entity_type=#{entityType}, std_name=#{stdName}, alias=#{alias}, summary=#{summary}, update_time=NOW()
WHERE id=#{id}

mapper.select:
SELECT * FROM wiki_entity
WHERE entity_type = #{type}
  AND (
      std_name = #{name}
      OR FIND_IN_SET(#{name}, REPLACE(REPLACE(alias, ' ', ''), '，', ',')) > 0
  )
LIMIT 1
